import SwiftUIclass MenuController: NSObject, ObservableObject{	@Published var showDeleteAlert: Bool = false	@Published var showForexCalendar: Bool = false    @Published var showNotificationSettings: Bool = false    @Published var showProfile: Bool = false	@Published var showSettings: Bool = false    @Published var showTradeView: Bool = false    @Published var showAllTrades: Bool = UserDefaults.standard.bool(forKey: "showAllTrades") {        didSet{            UserDefaults.standard.set(self.showAllTrades, forKey: "showAllTrades")        }    }    @Published var showWeekTrades: Bool = UserDefaults.standard.bool(forKey: "showWeekTrades") {        didSet{            UserDefaults.standard.set(self.showWeekTrades, forKey: "showWeekTrades")        }    }}